// Layout constants
const COLUMN_WIDTH = 300;
const GAP_Y = 24;
const STRIDE_X = COLUMN_WIDTH + 24; // GAP_X=24

// Big plane + edge recenter
const PLANE_W = 10_000_000;
const PLANE_H = 10_000_000;
const EDGE_GUARD = 2_000_000;

const COL_BUFFER = 2;
const ROW_BUFFER = 2;

// Scrolling pace (slow + eased)
const WHEEL_SPEED = 0.4;
const TOUCH_SPEED = 0.5;
const CLAMP_MAX_DELTA = 60;
const EASE_K = 0.18;
const STOP_EPS = 0.1;
const clamp = (n: number, max: number) => Math.max(-max, Math.min(max, n));

// -------- hooks & layout helpers ----------
function useViewport<T extends HTMLElement>(
  elRef: React.RefObject<T | null> | React.MutableRefObject<T | null>
) {
  const [size, setSize] = useState({ w: 1200, h: 800 });
  useEffect(() => {
    const update = () => {
      const el = elRef.current;
      if (!el) return;
      setSize({ w: el.clientWidth, h: el.clientHeight });
    };
    update();
    window.addEventListener("resize", update, { passive: true });
    return () => window.removeEventListener("resize", update);
  }, [elRef]);
  return size;
}

type HeightsMap = Record<string, number>;

function buildMasonryColumns(
  cards: typeof baseCardData,
  colCount: number,
  measured: HeightsMap
) {
  type C = (typeof cards)[number] & { _h: number };
  const cols: C[][] = Array.from({ length: colCount }, () => []);
  const heights = new Array(colCount).fill(0);

  // Use measured height if available; fallback to Tailwind guess.
  const xs: C[] = cards.map((c) => ({
    ...c,
    _h: measured[c.id] ?? HEIGHT_PX[c.height as keyof typeof HEIGHT_PX] ?? 256,
  }));

  for (const c of xs) {
    let k = 0;
    for (let i = 1; i < colCount; i++) if (heights[i] < heights[k]) k = i;
    cols[k].push(c);
    heights[k] += c._h + GAP_Y;
  }

  const cumY = cols.map((col) => {
    const offs: number[] = [];
    let y = 0;
    for (const c of col) {
      offs.push(y);
      y += c._h + GAP_Y;
    }
    return offs;
  });

  const colHeights = cols.map(
    (col) => col.reduce((acc, c) => acc + c._h, 0) + GAP_Y * Math.max(0, col.length - 1)
  );

  return { cols, cumY, colHeights };
}

// --------------- component ----------------
export default function PinterestMasonry() {
  const scrollerRef = useRef<HTMLDivElement>(null);
  const planeRef = useRef<HTMLDivElement>(null);

  // NEW: hidden measurer to get real DOM heights
  const measureRef = useRef<HTMLDivElement>(null);
  const [measuredHeights, setMeasuredHeights] = useState<HeightsMap>({});

  const { w: vw, h: vh } = useViewport(scrollerRef);
  const [columns, setColumns] = useState(4);

  // virtual origin & recentering
  const originX = useRef(0);
  const originY = useRef(0);
  const recentering = useRef(false);

  // easing state
  const targetRef = useRef({ x: 0, y: 0 });
  const rafRef = useRef<number>(0);

  // responsive columns
  useEffect(() => {
    const w = scrollerRef.current?.clientWidth ?? window.innerWidth;
    if (w < 640) setColumns(2);
    else if (w < 768) setColumns(3);
    else if (w < 1024) setColumns(4);
    else setColumns(5);
  }, [vw]);

  // Measure real heights (updates whenever content/fonts/images settle)
  useLayoutEffect(() => {
    const root = measureRef.current;
    if (!root) return;

    const readHeights = () => {
      const next: HeightsMap = {};
      Array.from(root.children).forEach((child) => {
        const el = child as HTMLElement;
        const id = el.dataset.id!;
        next[id] = Math.round(el.getBoundingClientRect().height);
      });
      if (Object.keys(next).length) setMeasuredHeights(next);
    };

    // Use ResizeObserver so late-loading images/canvas update heights
    const ro = new ResizeObserver(() => readHeights());
    ro.observe(root);
    Array.from(root.children).forEach((ch) => ro.observe(ch));
    // Initial read
    readHeights();

    return () => ro.disconnect();
  }, [columns]);

  const layout = useMemo(
    () => buildMasonryColumns(baseCardData as any, columns, measuredHeights),
    [columns, measuredHeights]
  );

  // Center the scroller on first mount
  useLayoutEffect(() => {
    const s = scrollerRef.current;
    if (!s) return;
    const cx = (PLANE_W - s.clientWidth) / 2;
    const cy = (PLANE_H - s.clientHeight) / 2;
    s.scrollLeft = cx;
    s.scrollTop = cy;
    originX.current = -cx;
    originY.current = -cy;
    targetRef.current = { x: cx, y: cy };
  }, []);

  // Smooth scroller engine (RAF)
  useEffect(() => {
    const s = scrollerRef.current;
    if (!s) return;

    const step = () => {
      const tx = targetRef.current.x;
      const ty = targetRef.current.y;
      const nx = s.scrollLeft + (tx - s.scrollLeft) * EASE_K;
      const ny = s.scrollTop + (ty - s.scrollTop) * EASE_K;
      const closeX = Math.abs(tx - s.scrollLeft) < STOP_EPS;
      const closeY = Math.abs(ty - s.scrollTop) < STOP_EPS;
      s.scrollLeft = closeX ? tx : nx;
      s.scrollTop = closeY ? ty : ny;
      if (!closeX || !closeY) rafRef.current = requestAnimationFrame(step);
      else rafRef.current = 0;
    };

    const ensureRAF = () => {
      if (!rafRef.current) rafRef.current = requestAnimationFrame(step);
    };

    const onWheel = (e: WheelEvent) => {
      if (e.ctrlKey) return;
      e.preventDefault();
      let { deltaX: dx, deltaY: dy, deltaMode } = e;
      if (deltaMode === 1) { const LINE = 16; dx *= LINE; dy *= LINE; }
      else if (deltaMode === 2) { const PAGE = s.clientHeight; dx *= PAGE; dy *= PAGE; }
      targetRef.current.x += clamp(dx * WHEEL_SPEED, CLAMP_MAX_DELTA);
      targetRef.current.y += clamp(dy * WHEEL_SPEED, CLAMP_MAX_DELTA);
      ensureRAF();
    };

    let active = false, lastX = 0, lastY = 0;
    const onStart = (e: TouchEvent) => {
      if (e.touches.length !== 1) return;
      active = true;
      lastX = e.touches[0].clientX;
      lastY = e.touches[0].clientY;
      targetRef.current.x = s.scrollLeft;
      targetRef.current.y = s.scrollTop;
    };
    const onMove = (e: TouchEvent) => {
      if (!active || e.touches.length !== 1) return;
      e.preventDefault();
      const x = e.touches[0].clientX, y = e.touches[0].clientY;
      targetRef.current.x += clamp((lastX - x) * TOUCH_SPEED, CLAMP_MAX_DELTA);
      targetRef.current.y += clamp((lastY - y) * TOUCH_SPEED, CLAMP_MAX_DELTA);
      lastX = x; lastY = y; ensureRAF();
    };
    const onEnd = () => { active = false; };

    const onKeyDown = (e: KeyboardEvent) => {
      const h = s.clientHeight, w = s.clientWidth;
      let dx = 0, dy = 0, used = true;
      switch (e.key) {
        case "ArrowDown": dy = h * 0.15; break;
        case "ArrowUp":   dy = -h * 0.15; break;
        case "PageDown":  dy = h * 0.7; break;
        case "PageUp":    dy = -h * 0.7; break;
        case "ArrowRight": dx = w * 0.15; break;
        case "ArrowLeft":  dx = -w * 0.15; break;
        case "Home":      targetRef.current.y = 0; break;
        case "End":       targetRef.current.y = PLANE_H - h; break;
        default: used = false;
      }
      if (used) { e.preventDefault(); targetRef.current.x += dx; targetRef.current.y += dy; ensureRAF(); }
    };

    s.addEventListener("wheel", onWheel, { passive: false, capture: true });
    s.addEventListener("touchstart", onStart, { passive: false });
    s.addEventListener("touchmove", onMove, { passive: false });
    s.addEventListener("touchend", onEnd);
    s.addEventListener("touchcancel", onEnd);
    document.addEventListener("keydown", onKeyDown, { passive: false, capture: true });

    return () => {
      s.removeEventListener("wheel", onWheel, { capture: true } as any);
      s.removeEventListener("touchstart", onStart);
      s.removeEventListener("touchmove", onMove);
      s.removeEventListener("touchend", onEnd);
      s.removeEventListener("touchcancel", onEnd);
      document.removeEventListener("keydown", onKeyDown, { capture: true } as any);
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
      rafRef.current = 0;
    };
  }, []);

  // Scroll state → tile math
  const [scroll, setScroll] = useState({ x: 0, y: 0 });
  useEffect(() => {
    const s = scrollerRef.current;
    if (!s) return;
    let ticking = false;
    const onScroll = () => {
      if (!ticking) {
        requestAnimationFrame(() => {
          setScroll({ x: s.scrollLeft, y: s.scrollTop });
          ticking = false;
        });
        ticking = true;
      }
    };
    s.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => s.removeEventListener("scroll", onScroll);
  }, []);

  // Invisible recenter
  useLayoutEffect(() => {
    const s = scrollerRef.current;
    if (!s) return;
    if (receneringGuard()) return;

    const sl = s.scrollLeft, st = s.scrollTop;
    const leftEdge = EDGE_GUARD, rightEdge = PLANE_W - vw - EDGE_GUARD;
    const topEdge = EDGE_GUARD, bottomEdge = PLANE_H - vh - EDGE_GUARD;
    const cx = (PLANE_W - vw) / 2, cy = (PLANE_H - vh) / 2;

    let dx = 0, dy = 0, need = false;
    if (sl < leftEdge) { dx = sl - cx; need = true; } else if (sl > rightEdge) { dx = sl - cx; need = true; }
    if (st < topEdge)  { dy = st - cy; need = true; } else if (st > bottomEdge) { dy = st - cy; need = true; }

    if (need) {
      recentering.current = true;
      originX.current += dx;
      originY.current += dy;
      s.scrollLeft = cx;
      s.scrollTop = cy;
      targetRef.current.x = cx;
      targetRef.current.y = cy;
      requestAnimationFrame(() => { recentering.current = false; });
    }

    function receneringGuard() { return recentering.current; }
  }, [scroll.x, scroll.y, vw, vh]);

  // Virtual camera position
  const virtualX = originX.current + scroll.x;
  const virtualY = originY.current + scroll.y;

  // Columns to render
  const firstCol = Math.floor(virtualX / STRIDE_X) - COL_BUFFER;
  const visColCount = Math.ceil(vw / STRIDE_X) + COL_BUFFER * 2;

  return (
    <div ref={scrollerRef} className="fixed inset-0 overflow-auto">
      {/* Hidden measurer: render one of each card at actual column width and read real heights */}
      <div
        ref={measureRef}
        aria-hidden
        className="fixed -left-[99999px] top-0 w-[300px] pointer-events-none opacity-0"
        style={{ width: COLUMN_WIDTH }}
      >
        {baseCardData.map((card) => (
          <div key={`measure-${card.id}`} data-id={card.id} style={{ width: COLUMN_WIDTH }}>
            <PinterestCard {...card} />
          </div>
        ))}
      </div>

      <div ref={planeRef} className="relative" style={{ width: PLANE_W, height: PLANE_H }}>
        {Array.from({ length: visColCount }).map((_, i) => {
          const colIndex = firstCol + i;
          const baseCol = ((colIndex % columns) + columns) % columns;
          const x = Math.round(colIndex * STRIDE_X - originX.current);

          const colCards = layout.cols[baseCol];
          const cumY = layout.cumY[baseCol];
          const patternH = layout.colHeights[baseCol] || 1;

          const firstRepeat = Math.floor(virtualY / patternH) - ROW_BUFFER;
          const repeatCount = Math.ceil(vh / patternH) + ROW_BUFFER * 2;

          return (
            <div key={`col-${colIndex}`} className="absolute top-0" style={{ left: x, width: COLUMN_WIDTH }}>
              {Array.from({ length: repeatCount }).map((__, ry) => {
                const rep = firstRepeat + ry;
                const yBase = rep * patternH;

                return colCards.map((card, idx) => {
                  const y = Math.round(yBase + cumY[idx] - originY.current);
                  return (
                    <div
                      key={`tile-${colIndex}-${rep}-${card.id}-${idx}`}
                      className="absolute [&>*]:m-0"  // ensure no external margins from card root
                      style={{
                        top: y,
                        width: COLUMN_WIDTH,
                        willChange: "transform",
                        transform: "translateZ(0)",
                      }}
                    >
                      <PinterestCard {...card} />
                    </div>
                  );
                });
              })}
            </div>
          );
        })}
      </div>
    </div>
  );
}
